73	json common_chat_msg::to_json_oaicompat(bool concat_typed_text) const {
74	    if (!content.empty() && !content_parts.empty()) {
75	        throw std::runtime_error("Cannot specify both content and content_parts");
76	    }
77	    json jmsg {
78	        {"role", role},
79	    };
80	    if (!content.empty()) {
81	        jmsg["content"] = content;
82	    } else if (!content_parts.empty()) {
83	        if (concat_typed_text) {
84	            std::string text;
85	            bool last_was_media_marker = false;
86	            // join parts with newline, do not add newline before or after media markers
87	            for (const auto & part : content_parts) {
88	                bool add_new_line = true;
89	                if (part.type == "text") {
90	                    add_new_line = !last_was_media_marker && !text.empty();
91	                    last_was_media_marker = false;
92	                } else if (part.type == "media_marker") {
93	                    add_new_line = false;
94	                    last_was_media_marker = true;
95	                } else {
96	                    LOG_WRN("Ignoring content part type: %s\n", part.type.c_str());
97	                    continue;
98	                }
99	
100	                if (add_new_line) {
101	                    text += '\n';
102	                }
103	
104	                text += part.text;
105	            }
106	            jmsg["content"] = text;
107	        } else {
108	            auto & parts = jmsg["content"] = json::array();
109	            for (const auto & part : content_parts) {
110	                parts.push_back({
111	                    {"type", part.type},
112	                    {"text", part.text},
113	                });
114	            }
115	        }
116	    } else {
117	        jmsg["content"] = "";
118	    }
119	    if (!reasoning_content.empty()) {
120	        jmsg["reasoning_content"] = reasoning_content;
121	    }
122	    if (!tool_name.empty()) {
123	        jmsg["name"] = tool_name;
124	    }
125	    if (!tool_call_id.empty()) {
126	        jmsg["tool_call_id"] = tool_call_id;
127	    }
128	    if (!tool_calls.empty()) {
129	        jmsg["tool_calls"] = json::array();
130	        auto & jtool_calls = jmsg["tool_calls"];
131	        for (const auto & tool_call : tool_calls) {
132	            json tc {
133	                {"type", "function"},
134	                {"function", {
135	                    {"name", tool_call.name},
136	                    {"arguments", json(tool_call.arguments)},
137	                }},
138	            };
139	            if (!tool_call.id.empty()) {
140	                tc["id"] = tool_call.id;
141	            }
142	            // Some templates generate and require an id (sometimes in a very specific format, e.g. Mistral Nemo).
143	            // We only generate a random id for the ones that don't generate one by themselves
144	            // (they also won't get to see it as their template likely doesn't use it, so it's all for the client)
145	            // {"id", tc.id.empty() ? gen_tool_call_id() : tc.id},
146	            jtool_calls.push_back(tc);
147	        }
148	    }
149	
150	    return jmsg;
151	}
