435	json common_chat_tools_to_json_oaicompat(const std::vector<common_chat_tool> & tools) {
436	    if (tools.empty()) {
437	        return json();
438	    }
439	
440	    auto result = json::array();
441	    for (const auto & tool : tools) {
442	        result.push_back({
443	            { "type",     "function" },
444	            { "function",
445	             {
446	                  { "name", tool.name },
447	                  { "description", tool.description },
448	                  { "parameters", json::parse(tool.parameters) },
449	              }                      },
450	        });
451	    }
452	    return result;
453	}
