591	common_chat_templates_ptr common_chat_templates_init(const struct llama_model * model,
592	                                                     const std::string &        chat_template_override,
593	                                                     const std::string &        bos_token_override,
594	                                                     const std::string &        eos_token_override) {
595	    std::string default_template_src;
596	    std::string template_tool_use_src;
597	
598	    bool has_explicit_template = !chat_template_override.empty();
599	    if (chat_template_override.empty()) {
600	        GGML_ASSERT(model != nullptr);
601	        const auto * str = llama_model_chat_template(model, /* name */ nullptr);
602	        if (str) {
603	            default_template_src  = str;
604	            has_explicit_template = true;
605	        }
606	        str = llama_model_chat_template(model, /* name */ "tool_use");
607	        if (str) {
608	            template_tool_use_src = str;
609	            has_explicit_template = true;
610	        }
611	    } else {
612	        default_template_src = chat_template_override;
613	    }
614	    if (default_template_src.empty() || default_template_src == "chatml") {
615	        if (!template_tool_use_src.empty()) {
616	            default_template_src = template_tool_use_src;
617	        } else {
618	            default_template_src = CHATML_TEMPLATE_SRC;
619	        }
620	    }
621	
622	    // TODO @ngxson : this is a temporary hack to prevent chat template from throwing an error
623	    // Ref: https://github.com/ggml-org/llama.cpp/pull/15230#issuecomment-3173959633
624	    if (default_template_src.find("<|channel|>") != std::string::npos
625	        // search for the error message and patch it
626	        && default_template_src.find("in message.content or") != std::string::npos) {
627	        string_replace_all(default_template_src,
628	                           "{%- if \"<|channel|>analysis<|message|>\" in message.content or "
629	                           "\"<|channel|>final<|message|>\" in message.content %}",
630	                           "{%- if false %}");
631	    }
632	
633	    // TODO @aldehir : this is a temporary fix, pending Minja changes
634	    // Ref: https://github.com/ggml-org/llama.cpp/pull/17713#issuecomment-3631342664
635	    if (default_template_src.find("[TOOL_CALLS]") != std::string::npos
636	        // search for the error message and patch it
637	        && default_template_src.find("if (message['content'] is none or") != std::string::npos) {
638	        string_replace_all(default_template_src,
639	                           "{%- if (message['content'] is none or message['content'] == '' or "
640	                           "message['content']|length == 0) and (message['tool_calls'] is not defined or "
641	                           "message['tool_calls'] is none or message['tool_calls']|length == 0) %}",
642	                           "{%- if false %}");
643	    }
644	
645	    std::string token_bos = bos_token_override;
646	    std::string token_eos = eos_token_override;
647	    bool        add_bos   = false;
648	    bool        add_eos   = false;
649	    if (model) {
650	        const auto * vocab     = llama_model_get_vocab(model);
651	        const auto   get_token = [&](llama_token token, const char * name, const char * jinja_variable_name) {
652	            if (token == LLAMA_TOKEN_NULL) {
653	                if (default_template_src.find(jinja_variable_name) != std::string::npos ||
654	                    template_tool_use_src.find(jinja_variable_name) != std::string::npos) {
655	                    LOG_WRN(
656	                        "common_chat_templates_init: warning: vocab does not have a %s token, jinja template won't "
657	                          "work as intended.\n",
658	                        name);
659	                }
660	                return std::string();
661	            }
662	            return common_token_to_piece(vocab, token, true);
663	        };
664	        token_bos = get_token(llama_vocab_bos(vocab), "BOS", "bos_token");
665	        token_eos = get_token(llama_vocab_eos(vocab), "EOS", "eos_token");
666	        add_bos   = llama_vocab_get_add_bos(vocab);
667	        add_eos   = llama_vocab_get_add_eos(vocab);
668	    }
669	    common_chat_templates_ptr tmpls(new common_chat_templates());
670	    tmpls->has_explicit_template = has_explicit_template;
671	    tmpls->add_bos               = add_bos;
672	    tmpls->add_eos               = add_eos;
673	    try {
674	        tmpls->template_default = std::make_unique<common_chat_template>(default_template_src, token_bos, token_eos);
675	    } catch (const std::exception & e) {
676	        LOG_ERR("%s: error: %s\n", __func__, e.what());
677	        LOG_ERR("%s: failed to initialize chat template\n", __func__);
678	        LOG_ERR("%s: please consider disabling jinja via --no-jinja, or using another chat template\n", __func__);
679	        throw e;
680	    }
681	    if (!template_tool_use_src.empty()) {
682	        try {
683	            tmpls->template_tool_use = std::make_unique<common_chat_template>(template_tool_use_src, token_bos, token_eos);
684	        } catch (const std::exception & e) {
685	            LOG_ERR("%s: failed to parse tool use chat template (ignoring it): %s\n", __func__, e.what());
686	        }
687	    }
688	    return tmpls;
689	}
