802	    // render
803	    jinja::runtime runtime(ctx);
804	    const jinja::value results = runtime.execute(tmpl.prog);
805	    auto parts = jinja::runtime::gather_string_parts(results);
806	
807	    std::string result = parts->as_string().str();
808	
809	    // TODO: improve this later
