103	    std::ifstream fs(path, std::ios_base::binary);
104	    if (!fs.is_open()) {
105	        fs = std::ifstream("../" + path, std::ios_base::binary);
106	        if (!fs.is_open()) {
107	            throw std::runtime_error("Failed to open file: " + path);
108	        }
109	    }
110	    fs.seekg(0, std::ios_base::end);
111	    auto size = fs.tellg();
112	    fs.seekg(0);
113	    std::string out;
114	    out.resize(static_cast<size_t>(size));
115	    fs.read(out.data(), static_cast<std::streamsize>(size));
116	    return out;
117	}
