```cpp
// Build up messages to follow the format:
// https://huggingface.co/mistralai/Ministral-3-14B-Reasoning-2512/blob/main/chat_template.jinja

auto adjusted_messages = json::array();
for (const auto & msg : inputs.messages) {
    auto role = msg.value("role", "");
    if (role != "system" && role != "assistant") {
        adjusted_messages.push_back(msg);  // Keep user messages as-is
        continue;
    }

    auto content = json::array();  // Create content as array of blocks

    // Add reasoning_content as "thinking" block
    if (msg.contains("reasoning_content") && msg.at("reasoning_content").is_string()) {
        content.push_back({
            { "type",     "thinking" },
            { "thinking", msg.at("reasoning_content").get<std::string>() },
        });
    }

    // Add content as "text" block
    if (msg.contains("content")) {
        if (msg.at("content").is_string()) {
            content.push_back({
                { "type", "text" },
                { "text", msg.at("content").get<std::string>() },
            });
        } else if (msg.at("content").is_array()) {
            auto blocks = msg.at("content");
            content.insert(content.end(), blocks.begin(), blocks.end());
        }
    }

    auto adjusted = msg;
    adjusted["content"] = content;
    adjusted.erase("reasoning_content");
    adjusted_messages.push_back(adjusted);
}
```

**Parser Structure:**
```cpp
data.supports_thinking  = true;
data.thinking_start_tag = "[THINK]";
data.thinking_end_tag   = "[/THINK]";
data.prompt            = common_chat_template_direct_apply_impl(
    tmpl, inputs, /* messages_override = */ adjusted_messages);
data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
data.preserved_tokens  = {
    "[THINK]",
    "[/THINK]",
    "[TOOL_CALLS]",
    "[ARGS]",
};
```

**Key Details:**
- **Message Transformation:** Converts `reasoning_content` field to `thinking` blocks
- **Block Structure:** Represents messages as arrays of content blocks (type + content)
- **Thinking Support:** Natively supports thinking markers `[THINK]...[/THINK]`
- **Tool Calls:** Uses `[TOOL_CALLS]` to introduce tool calls, `[ARGS]` for arguments
- **JSON Schema Support:** Can emit JSON responses wrapped in ` ```json...``` ` code fences
- **Grammar Integration:** Generates grammar constraints for tool calling and JSON schemas

